/**
 * Dev-stack state file — read/write `.claude/state/dev-stack.json`.
 * M125 #1: tracks PIDs and named subdomain for `/ork:dev` lab-stack boot.
 *
 * Schema:
 *   {
 *     bootedAt: ISO timestamp,
 *     branch: string,
 *     subdomain: string,                  // e.g. "feat-login.localhost"
 *     baseUrl: string,                    // e.g. "https://feat-login.localhost"
 *     processes: {
 *       portless?:      { pid, command }
 *       emulate?:       { pid, command }
 *       devServer?:     { pid, command }
 *       agentBrowser?:  { sessionName, pid? }
 *     }
 *     emulators: string[]                 // service names from emulate-seed
 *   }
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, rmSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { getProjectDir } from './env.js';

export interface DevStackProcess {
  pid?: number;
  command?: string;
  sessionName?: string;
}

export interface DevStackState {
  bootedAt: string;
  branch: string;
  subdomain: string;
  baseUrl: string;
  processes: {
    portless?: DevStackProcess;
    emulate?: DevStackProcess;
    devServer?: DevStackProcess;
    agentBrowser?: DevStackProcess;
  };
  emulators: string[];
}

function statePath(): string {
  return join(getProjectDir(), '.claude', 'state', 'dev-stack.json');
}

export function readDevStackState(): DevStackState | null {
  const path = statePath();
  if (!existsSync(path)) return null;
  try {
    return JSON.parse(readFileSync(path, 'utf8')) as DevStackState;
  } catch {
    return null;
  }
}

export function writeDevStackState(state: DevStackState): void {
  const path = statePath();
  mkdirSync(dirname(path), { recursive: true });
  writeFileSync(path, `${JSON.stringify(state, null, 2)}\n`);
}

export function clearDevStackState(): void {
  const path = statePath();
  if (existsSync(path)) rmSync(path);
}

/**
 * Predicate: is the boot stack currently considered live?
 * Returns true if state file exists AND any tracked PID is still running.
 */
export function isDevStackLive(): boolean {
  const state = readDevStackState();
  if (!state) return false;
  for (const proc of Object.values(state.processes)) {
    const pid = proc?.pid;
    if (typeof pid === 'number') {
      try {
        process.kill(pid, 0); // signal 0 = liveness probe
        return true;
      } catch {
      }
    }
  }
  return false;
}
